useEffect(() => {
  if (!pendingFormData) return;
  if (searchParams?.origin && searchParams?.destination) {
    navigate('/search');
    setPendingFormData(null);
  } else {
    setPendingFormData(null);
  }
}, [pendingFormData, searchParams, navigate]);

